 25→/**
 26→ * 請假/銷假單列表條件查詢 Processor
 27→ * <p>
 28→ * 提供 TM003 主頁面的假單查詢功能，支援多條件篩選與分頁。
 29→ * API 路徑：POST /api/tmLeaveQuery
 30→ * <p>
 31→ * 查詢條件（皆為選填）：
 32→ * - deptCode:        部門 ID（Integer，精準比對）
 33→ * - empAccount:      員工編號（String，模糊比對）
 34→ * - empName:         員工姓名（String，模糊比對）
 35→ * - beginDate:       查詢期間起（String，yyyy-MM-dd，預設當年 01-01）
 36→ * - endDate:         查詢期間迄（String，yyyy-MM-dd，預設當年 12-31）
 37→ * - leaveStatus:     簽核狀態（E01:申請, E02:核准, E03:退件, E04:註銷）
 38→ * - vacationCode:    假別代碼（String，精準比對）
 39→ * - vacationSubCode: 公假細項代碼（String，精準比對）
 40→ * <p>
 41→ * 回應欄位（data.records 陣列，每筆）：
 42→ * - empLeaveId:      假單流水號（前端明細跳轉使用）
 43→ * - empVacationId:   員工年度假別額度 ID
 44→ * - deptName:        部門名稱
 45→ * - empAccount:      員工編號
 46→ * - empNameCh:       員工中文姓名
 47→ * - empNameEn:       員工英文姓名
 48→ * - vacationCode:    假別代碼
 49→ * - vacationName:    假別名稱
 50→ * - vacationSubCode: 假別細項代碼
 51→ * - vacationSubName: 假別細項名稱
 52→ * - beginTime:       請假起始時間（yyyy-MM-dd HH:mm:ss）
 53→ * - endTime:         請假結束時間（yyyy-MM-dd HH:mm:ss）
 54→ * - leaveHours:      實際請假時數（扣除午休，0.5 為最小單位）
 55→ * - leaveStatus:     簽核狀態代碼
 56→ * - canCancel:       是否可銷假（true = 申請中 E01）
 57→ * - attachment:      是否有附件
 58→ * <p>
 59→ * 權限：USER 僅能查詢自己；ADMIN 可查詢所有人（依 AU_ROLE_DETAIL.ROLE_CODE 判斷）
 60→ *
 61→ * @author SoeTek Team
 62→ * @since 2026-03-23
 63→ */
 64→@Slf4j
 65→@ApplicationScoped
 66→@Named("tmLeaveQueryProcessor")
 67→@RegisterForReflection
 68→public class TmLeaveQueryProcessor extends ApiRouteProcessor {
 69→
 70→    private static final int DEFAULT_PER_PAGE = 5;
 71→
 72→    @Inject
 73→    TmLeaveQueryService leaveQueryService;
 74→
 75→    @Override
 76→    public Map<String, Object> getTemplateParams() {
 77→        return Map.of(
 78→                "routeId", "tmLeaveQuery",
 79→                "apiDescription", "查詢請假/銷假單列表",
 80→                "requiredFields", ""
 81→        );
 82→    }
 83→
 84→    @Override
 85→    protected String getProcessorType() {
 86→        return LogType.API_PROCESSING;
 87→    }
 88→
 89→    @Override
 90→    @ActivateRequestContext
 91→    @AuditLog(
 92→            operation = AuditLog.OperationType.QUERY,
 93→            entity = "TmEmpLeave",
 94→            description = "查詢請假/銷假單列表",
 95→            logParameters = true,
 96→            logResult = true
 97→    )
 98→    public Object process(Exchange exchange, @Body Map<String, Object> payload,
 99→                          @Headers Map<String, Object> headers) throws Exception {
100→        return executeWithErrorHandling(exchange, payload, headers);
101→    }
102→
103→    @Override
104→    protected Object processBusinessLogic(
105→            Exchange exchange,
106→            Map<String, Object> payload,
107→            Map<String, Object> headers,
108→            String traceId,
109→            String routeId) throws Exception {
110→
111→        // 1. 取得當前登入使用者（由 HandlerApiResource 注入至 X-User header）
112→        String currentUser = headers.getOrDefault("X-User", "").toString().trim();
113→        log.debug("[請假單查詢] 開始 - currentUser: {}, TraceId: {}", currentUser, traceId);
114→
115→        // 2. 判斷角色（ADMIN/USER）
116→        boolean isAdmin = leaveQueryService.isAdminRole(currentUser);
117→        log.debug("[請假單查詢] 角色判斷完成 - isAdmin: {}, TraceId: {}", isAdmin, traceId);
118→
119→        // 3. 套用預設查詢期間（前端未傳入時預設為當年度）
120→        applyDefaultDateRange(payload);
121→
122→        // 4. 套用預設分頁大小（規格：每頁 5 筆）
123→        applyDefaultPerPage(payload);
124→
125→        // 5. 解析分頁參數
126→        PaginationParams paginationParams = PaginationUtil.parsePaginationParams(payload);
127→
128→        // 6. 呼叫 Service 執行跨表查詢
129→        List<Map<String, Object>> records =
130→                leaveQueryService.queryLeaveList(payload, currentUser, isAdmin);
131→
132→        log.debug("[請假單查詢] 查詢完成 - 總筆數: {}, TraceId: {}", records.size(), traceId);
133→
134→        // 7. 執行記憶體分頁
135→        PaginationResult<Map<String, Object>> result =
136→                PaginationUtil.paginate(records, paginationParams);
137→
138→        log.info("[請假單查詢] 成功 - TotalCount: {}, CurrentPage: {}, PerPage: {}, TraceId: {}",
139→                result.getTotalCount(), result.getCurrentPage(), paginationParams.getPerPage(), traceId);
140→
141→        // 8. 組裝標準回應
142→        Map<String, Object> response = new HashMap<>(result.toResponseMap("查詢成功"));
143→        response.put("traceId", traceId);
144→
145→        // 9. items → records（符合前端慣例）
146→        @SuppressWarnings("unchecked")
147→        Map<String, Object> data = (Map<String, Object>) response.get("data");
148→        if (data != null && data.containsKey("items")) {
149→            Map<String, Object> enhancedData = new HashMap<>(data);
150→            enhancedData.put("records", enhancedData.remove("items"));
151→            response.put("data", enhancedData);
152→        }
153→
154→        return response;
155→    }
156→
157→    // ==================== 私有輔助方法 ====================
158→
159→    /**
160→     * 若前端未傳入查詢期間，自動補入當年度首尾日期（規格 Q3:B）
161→     */
162→    private void applyDefaultDateRange(Map<String, Object> payload) {
163→        int currentYear = LocalDate.now().getYear();
164→        String defaultBegin = currentYear + "-01-01";
165→        String defaultEnd   = currentYear + "-12-31";
166→
167→        Object beginDate = payload.get("beginDate");
168→        if (beginDate == null || beginDate.toString().trim().isEmpty()
169→                || "null".equalsIgnoreCase(beginDate.toString().trim())) {
170→            payload.put("beginDate", defaultBegin);
171→            log.debug("[請假單查詢] 未傳入 beginDate，套用預設: {}", defaultBegin);
172→        }
173→
174→        Object endDate = payload.get("endDate");
175→        if (endDate == null || endDate.toString().trim().isEmpty()
176→                || "null".equalsIgnoreCase(endDate.toString().trim())) {
177→            payload.put("endDate", defaultEnd);
178→            log.debug("[請假單查詢] 未傳入 endDate，套用預設: {}", defaultEnd);
179→        }
180→    }
181→
182→    /**
183→     * 若前端未傳入 perPage，套用規格預設值（每頁 5 筆）
184→     */
185→    private void applyDefaultPerPage(Map<String, Object> payload) {
186→        Object perPage = payload.get("perPage");
187→        if (perPage == null || perPage.toString().trim().isEmpty()
188→                || "null".equalsIgnoreCase(perPage.toString().trim())) {
189→            payload.put("perPage", DEFAULT_PER_PAGE);
190→        }
191→    }
192→}
