 20→/**
 21→ * 請假/銷假單列表查詢服務
 22→ * <p>
 23→ * 查詢主鏈：
 24→ * TM_EMP_LEAVE → TM_EMP_VACATION → PM_EMPLOYEE → AU_ORGANIZATION
 25→ *                               → TM_VACATION_DETAIL_SETTING → TM_VACATION_SETTING
 26→ * <p>
 27→ * 權限策略：
 28→ * - ADMIN (AU_ROLE_DETAIL.ROLE_CODE='ADMIN')：可查詢所有員工的假單
 29→ * - USER  (AU_ROLE_DETAIL.ROLE_CODE='USER') ：僅能查詢自己的假單
 30→ * <p>
 31→ * 查詢期間語意（交集）：l.BEGIN_TIME <= endDateTime AND l.END_TIME >= beginDateTime
 32→ * 請假時數計算：扣除每日午休 12:30～13:30（最小單位 0.5 小時）
 33→ *
 34→ * @author SoeTek Team
 35→ * @since 2026-03-23
 36→ */
 37→@Slf4j
 38→@ApplicationScoped
 39→public class TmLeaveQueryService {
 40→
 41→    private static final DateTimeFormatter DT_FORMATTER = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
 42→
 43→    @Inject
 44→    @PersistenceUnit("eap")
 45→    EntityManager em;
 46→
 47→    // ==================== 主要查詢 ====================
 48→
 49→    /**
 50→     * 查詢請假/銷假單列表
 51→     *
 52→     * @param criteria    查詢條件 Map（deptCode, empAccount, empName, beginDate, endDate,
 53→     *                    leaveStatus, vacationCode, vacationSubCode, sortBy, sortOrder）
 54→     * @param currentUser 當前登入帳號（由 X-User header 取得）
 55→     * @param isAdmin     是否為 ADMIN 角色
 56→     * @return 請假單列表，每筆含已計算之 leaveHours 與 canCancel 欄位
 57→     */
 58→    public List<Map<String, Object>> queryLeaveList(Map<String, Object> criteria,
 59→                                                     String currentUser,
 60→                                                     boolean isAdmin) {
 61→
 62→        log.info("[請假單查詢] 收到的 criteria: {}, currentUser: {}, isAdmin: {}",
 63→                criteria, currentUser, isAdmin);
 64→
 65→        // ── 解析查詢條件 ──
 66→        Integer deptCode       = extractInteger(criteria, "deptCode");
 67→        String  empAccount     = extractString(criteria,  "empAccount");
 68→        String  empName        = extractString(criteria,  "empName");
 69→        String  beginDate      = extractString(criteria,  "beginDate");
 70→        String  endDate        = extractString(criteria,  "endDate");
 71→        String  leaveStatus    = extractString(criteria,  "leaveStatus");
 72→        String  vacationCode   = extractString(criteria,  "vacationCode");
 73→        String  vacationSubCode= extractString(criteria,  "vacationSubCode");
 74→        String  sortBy         = extractString(criteria,  "sortBy");
 75→        String  sortOrder      = extractString(criteria,  "sortOrder");
 76→
 77→        log.info("[請假單查詢] 解析後 - dept:{}, empAcc:{}, empName:{}, begin:{}, end:{}, " +
 78→                 "status:{}, vacCode:{}, vacSubCode:{}",
 79→                deptCode, empAccount, empName, beginDate, endDate,
 80→                leaveStatus, vacationCode, vacationSubCode);
 81→
 82→        // ── 建立基底 SQL ──
 83→        StringBuilder sql = new StringBuilder("""
 84→                SELECT
 85→                    l.EMP_LEAVE_ID          AS empLeaveId,
 86→                    l.EMP_VACATION_ID       AS empVacationId,
 87→                    org.ORG_NAME            AS deptName,
 88→                    e.EMP_ACCOUNT           AS empAccount,
 89→                    e.EMP_NAME              AS empNameCh,
 90→                    e.EMP_NAME_EN           AS empNameEn,
 91→                    vs.VACATION_CODE        AS vacationCode,
 92→                    vs.VACATION_NAME        AS vacationName,
 93→                    vds.VACATION_SUB_CODE   AS vacationSubCode,
 94→                    vds.VACATION_SUB_NAME   AS vacationSubName,
 95→                    l.BEGIN_TIME            AS beginTime,
 96→                    l.END_TIME              AS endTime,
 97→                    l.LEAVE_STATUS          AS leaveStatus,
 98→                    l.ATTACHMENT            AS attachment
 99→                FROM EAP.TM_EMP_LEAVE l
100→                INNER JOIN EAP.TM_EMP_VACATION ev
101→                    ON ev.EMP_VACATION_ID = l.EMP_VACATION_ID
102→                INNER JOIN EAP.PM_EMPLOYEE e
103→                    ON e.EMP_ID = ev.EMP_ID
104→                LEFT JOIN EAP.AU_ORGANIZATION org
105→                    ON org.ORG_ID = e.ORG_ID
106→                INNER JOIN EAP.TM_VACATION_DETAIL_SETTING vds
107→                    ON vds.VACATION_SUB_ID = ev.VACATION_SUB_ID
108→                INNER JOIN EAP.TM_VACATION_SETTING vs
109→                    ON vs.VACATION_CODE = vds.VACATION_CODE
110→                WHERE 1=1
111→                """);
112→
113→        Map<String, Object> params = new LinkedHashMap<>();
114→
115→        // ── 權限過濾：USER 只能看自己 ──
116→        if (!isAdmin) {
117→            sql.append("  AND e.EMP_ACCOUNT = :currentUser\n");
118→            params.put("currentUser", currentUser);
119→        }
120→
121→        // ── 動態查詢條件 ──
122→        if (deptCode != null) {
123→            sql.append("  AND e.ORG_ID = :deptCode\n");
124→            params.put("deptCode", deptCode);
125→        }
126→
127→        if (empAccount != null) {
128→            sql.append("  AND e.EMP_ACCOUNT LIKE :empAccount\n");
129→            params.put("empAccount", "%" + empAccount + "%");
130→        }
131→
132→        if (empName != null) {
133→            sql.append("  AND e.EMP_NAME LIKE :empName\n");
134→            params.put("empName", "%" + empName + "%");
135→        }
136→
137→        // 查詢期間（交集邏輯：假單任意一部分落在查詢區間內即顯示）
138→        if (beginDate != null) {
139→            sql.append("  AND l.END_TIME >= :queryBegin\n");
140→            params.put("queryBegin", LocalDate.parse(beginDate).atStartOfDay());
141→        }
142→        if (endDate != null) {
143→            sql.append("  AND l.BEGIN_TIME <= :queryEnd\n");
144→            params.put("queryEnd", LocalDate.parse(endDate).atTime(23, 59, 59));
145→        }
146→
147→        if (leaveStatus != null) {
148→            sql.append("  AND l.LEAVE_STATUS = :leaveStatus\n");
149→            params.put("leaveStatus", leaveStatus);
150→        }
151→
152→        if (vacationCode != null) {
153→            sql.append("  AND vds.VACATION_CODE = :vacationCode\n");
154→            params.put("vacationCode", vacationCode);
155→        }
156→
157→        if (vacationSubCode != null) {
158→            sql.append("  AND vds.VACATION_SUB_CODE = :vacationSubCode\n");
159→            params.put("vacationSubCode", vacationSubCode);
160→        }
161→
162→        sql.append(buildOrderBy(sortBy, sortOrder));
163→
164→        log.debug("[請假單查詢] 最終 SQL: {}", sql);
165→
166→        // ── 執行查詢 ──
167→        Query query = em.createNativeQuery(sql.toString());
168→        params.forEach(query::setParameter);
169→
170→        @SuppressWarnings("unchecked")
171→        List<Object[]> rows = query.getResultList();
172→
173→        // ── 組裝回應 ──
174→        List<Map<String, Object>> result = new ArrayList<>(rows.size());
175→        for (Object[] row : rows) {
176→            result.add(mapRow(row));
177→        }
178→
179→        log.debug("[請假單查詢] 查詢完成，共 {} 筆", result.size());
180→        return result;
181→    }
182→
183→    // ==================== 角色判斷 ====================
184→
185→    /**
186→     * 判斷指定使用者是否具有 ADMIN 角色
187→     * 查詢 EAP.AU_ROLE_DETAIL.ROLE_CODE = 'ADMIN'
188→     *
189→     * @param userAccount 登入帳號
190→     * @return true = ADMIN，false = USER（含查詢失敗時安全降級）
191→     */
192→    public boolean isAdminRole(String userAccount) {
193→        if (userAccount == null || userAccount.isBlank()) return false;
194→        try {
195→            String sql = "SELECT COUNT(*) FROM EAP.AU_ROLE_DETAIL " +
196→                         "WHERE ROLE_CODE = 'ADMIN' AND ROLE_MEMBER = :account";
197→            Number count = (Number) em.createNativeQuery(sql)
198→                    .setParameter("account", userAccount)
199→                    .getSingleResult();
200→            return count.intValue() > 0;
201→        } catch (Exception e) {
202→            log.warn("[角色查詢] 查詢 ADMIN 角色失敗，安全降級為 USER - account: {}", userAccount, e);
203→            return false;
204→        }
205→    }
206→
207→    // ==================== 私有輔助方法 ====================
208→
209→    /**
210→     * 將 Object[] 一列資料映射為 Map
211→     * 對應 SQL SELECT 欄位順序（row[0]~row[13]）
212→     */
213→    private Map<String, Object> mapRow(Object[] row) {
214→        Map<String, Object> record = new HashMap<>();
215→
216→        record.put("empLeaveId",      row[0]);
217→        record.put("empVacationId",   row[1]);
218→        record.put("deptName",        row[2]);
219→        record.put("empAccount",      row[3]);
220→        record.put("empNameCh",       row[4]);
221→        record.put("empNameEn",       row[5]);
222→        record.put("vacationCode",    row[6]);
223→        record.put("vacationName",    row[7]);
224→        record.put("vacationSubCode", row[8]);
225→        record.put("vacationSubName", row[9]);
226→
227→        // 請假起訖時間（格式化為字串）
228→        LocalDateTime beginTime = toLocalDateTime(row[10]);
229→        LocalDateTime endTime   = toLocalDateTime(row[11]);
230→        record.put("beginTime", beginTime != null ? beginTime.format(DT_FORMATTER) : null);
231→        record.put("endTime",   endTime   != null ? endTime.format(DT_FORMATTER)   : null);
232→
233→        // 請假時數（扣除午休計算）
234→        record.put("leaveHours", calculateLeaveHours(beginTime, endTime));
235→
236→        // 簽核狀態
237→        String status = row[12] != null ? row[12].toString().trim() : "";
238→        record.put("leaveStatus", status);
239→
240→        // 是否可銷假（僅 E01:申請中 可銷）
241→        record.put("canCancel", "E01".equals(status));
242→
243→        // 是否有附件（MSSQL BIT 可能回傳 Boolean 或 Integer）
244→        record.put("attachment", parseBit(row[13]));
245→
246→        return record;
247→    }
248→
249→    /**
250→     * 計算實際請假時數，扣除每日午休（12:30 ～ 13:30）
251→     * 結果四捨五入至 0.5 小時（符合 TM_VACATION_DETAIL_SETTING.MIN_HOURS 精度）
252→     *
253→     * @param beginTime 請假起始時間
254→     * @param endTime   請假結束時間
255→     * @return 實際時數（0.5 為最小單位）
256→     */
257→    private double calculateLeaveHours(LocalDateTime beginTime, LocalDateTime endTime) {
258→        if (beginTime == null || endTime == null || !endTime.isAfter(beginTime)) {
259→            return 0.0;
260→        }
261→
262→        long rawMinutes = ChronoUnit.MINUTES.between(beginTime, endTime);
263→        long lunchDeductMinutes = 0;
264→
265→        // 逐日計算午休重疊分鐘數
266→        LocalDate day     = beginTime.toLocalDate();
267→        LocalDate lastDay = endTime.toLocalDate();
268→
269→        while (!day.isAfter(lastDay)) {
270→            LocalDateTime lunchStart = day.atTime(12, 30);
271→            LocalDateTime lunchEnd   = day.atTime(13, 30);
272→
273→            // 重疊區間 = max(beginTime, lunchStart) ~ min(endTime, lunchEnd)
274→            LocalDateTime overlapStart = beginTime.isAfter(lunchStart) ? beginTime : lunchStart;
275→            LocalDateTime overlapEnd   = endTime.isBefore(lunchEnd)    ? endTime   : lunchEnd;
276→
277→            if (overlapEnd.isAfter(overlapStart)) {
278→                lunchDeductMinutes += ChronoUnit.MINUTES.between(overlapStart, overlapEnd);
279→            }
280→            day = day.plusDays(1);
281→        }
282→
283→        long netMinutes = rawMinutes - lunchDeductMinutes;
284→        // 四捨五入至 0.5 小時（30 分鐘為單位）
285→        return Math.round(netMinutes / 30.0) * 0.5;
286→    }
